import { createClient, type SupabaseClient } from '@supabase/supabase-js';
import { ENV } from '@/core/constants';

let _supabase: SupabaseClient | null = null;

function getSupabase() {
  if (!_supabase) {
    _supabase = createClient(ENV.SUPABASE_URL, ENV.SUPABASE_SERVICE_KEY);
  }
  return _supabase;
}

function getBucket() {
  return ENV.SUPABASE_STORAGE_BUCKET;
}

/**
 * Upload file to Supabase Storage.
 * Returns the public URL of the uploaded file.
 */
export async function uploadFile(
  buffer: Buffer,
  fileName: string,
  mimeType: string,
): Promise<string> {
  const supabase = getSupabase();
  const bucket = getBucket();

  // Sanitize filename: remove special chars, keep extension
  const safeName = fileName.replace(/[^a-zA-Z0-9.\-_]/g, '_');
  const path = `${Date.now()}-${Math.random().toString(36).slice(2)}-${safeName}`;

  const { error } = await supabase.storage
    .from(bucket)
    .upload(path, buffer, {
      contentType: mimeType,
      upsert: false,
    });

  if (error) {
    console.error('Supabase upload error:', error);
    throw new Error(`Upload failed: ${error.message}`);
  }

  const { data } = supabase.storage.from(bucket).getPublicUrl(path);
  return data.publicUrl;
}

/**
 * Delete file from Supabase Storage by extracting path from public URL.
 */
export async function deleteFile(publicUrl: string): Promise<void> {
  const supabase = getSupabase();
  const bucket = getBucket();

  // URL format: https://{project}.supabase.co/storage/v1/object/public/{bucket}/{path}
  const parts = publicUrl.split(`/storage/v1/object/public/${bucket}/`);
  if (parts.length < 2) return;

  const path = parts[1];
  const { error } = await supabase.storage.from(bucket).remove([path]);
  if (error) console.error('Supabase delete error:', error);
}

import {
  Controller,
  Delete,
  Get,
  Param,
  Post,
  UploadedFiles,
  UseInterceptors,
  BadRequestException,
} from '@nestjs/common';
import { FilesInterceptor } from '@nestjs/platform-express';
import { ApiConsumes, ApiOperation, ApiTags } from '@nestjs/swagger';
import { memoryStorage } from 'multer';
import { ENDPOINTS, MSG } from '@/core/constants';
import { CurrentUser } from '@/core/decorators';
import { AuthUser } from '@/core/types';
import { AttachmentsService } from './attachments.service';

const MAX_SIZE = 10 * 1024 * 1024; // 10MB
const MAX_FILES = 10;

const ALLOWED_MIMES = [
  'image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml',
  'application/pdf',
  'application/zip', 'application/x-zip-compressed',
  'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.ms-excel', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'text/plain', 'text/csv',
];

// Issue-scoped routes: POST/GET /issues/:id/attachments
@ApiTags('Attachments')
@Controller(ENDPOINTS.ISSUES.BASE)
export class AttachmentsIssueController {
  constructor(private attachmentsService: AttachmentsService) {}

  @Post(ENDPOINTS.ISSUES.ATTACHMENTS)
  @UseInterceptors(
    FilesInterceptor('files', MAX_FILES, {
      storage: memoryStorage(),
      limits: { fileSize: MAX_SIZE },
      fileFilter: (_req, file, cb) => {
        if (ALLOWED_MIMES.includes(file.mimetype)) {
          cb(null, true);
        } else {
          cb(new BadRequestException('File type not allowed'), false);
        }
      },
    }),
  )
  @ApiConsumes('multipart/form-data')
  @ApiOperation({ summary: 'Upload file attachments to issue (max 10 files)' })
  async upload(
    @Param('id') issueId: string,
    @CurrentUser() user: AuthUser,
    @UploadedFiles() files: Express.Multer.File[],
  ) {
    if (!files || files.length === 0) throw new BadRequestException('No files uploaded');
    const attachments = await this.attachmentsService.uploadMany(issueId, user.id, files);
    return { message: MSG.SUCCESS.ATTACHMENT_UPLOADED, attachments };
  }

  @Get(ENDPOINTS.ISSUES.ATTACHMENTS)
  @ApiOperation({ summary: 'List attachments for issue' })
  findByIssue(@Param('id') issueId: string, @CurrentUser() user: AuthUser) {
    return this.attachmentsService.findByIssue(issueId, user.id);
  }
}

// Resource-scoped routes: DELETE /attachments/:id
@ApiTags('Attachments')
@Controller(ENDPOINTS.ATTACHMENTS.BASE)
export class AttachmentsManageController {
  constructor(private attachmentsService: AttachmentsService) {}

  @Delete(ENDPOINTS.ATTACHMENTS.BY_ID)
  @ApiOperation({ summary: 'Delete own attachment' })
  async delete(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    await this.attachmentsService.delete(id, user.id);
    return { message: MSG.SUCCESS.ATTACHMENT_DELETED };
  }
}

import { Module } from '@nestjs/common';
import { WorkspacesModule } from '@/modules/workspaces/workspaces.module';
import { AttachmentsIssueController, AttachmentsManageController } from './attachments.controller';
import { AttachmentsService } from './attachments.service';

@Module({
  imports: [WorkspacesModule],
  controllers: [AttachmentsIssueController, AttachmentsManageController],
  providers: [AttachmentsService],
})
export class AttachmentsModule {}

import {
  ForbiddenException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { ActivityAction } from '@prisma/client';
import { MSG, USER_SELECT_BASIC } from '@/core/constants';
import { PrismaService } from '@/core/database/prisma.service';
import { uploadFile, deleteFile } from '@/core/utils';
import { WorkspacesService } from '@/modules/workspaces/workspaces.service';

@Injectable()
export class AttachmentsService {
  constructor(
    private prisma: PrismaService,
    private workspacesService: WorkspacesService,
  ) {}

  async uploadMany(
    issueId: string,
    userId: string,
    files: Express.Multer.File[],
  ) {
    const issue = await this.prisma.issue.findUnique({
      where: { id: issueId },
      include: { project: { select: { workspaceId: true } } },
    });
    if (!issue) throw new NotFoundException(MSG.ERROR.ISSUE_NOT_FOUND);

    await this.workspacesService.assertMember(issue.project.workspaceId, userId);

    const attachments: Awaited<ReturnType<typeof this.prisma.attachment.create>>[] = [];

    for (const file of files) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
      const fileUrl: string = await uploadFile(
        file.buffer,
        file.originalname,
        file.mimetype,
      );

      const attachment = await this.prisma.attachment.create({
        data: {
          issueId,
          uploadedById: userId,
          fileName: file.originalname,
          fileUrl,
          fileSize: file.size,
          mimeType: file.mimetype,
        },
        include: { uploadedBy: USER_SELECT_BASIC },
      });

      attachments.push(attachment);
    }

    // Log single activity for batch upload
    const fileNames = files.map((f) => f.originalname).join(', ');
    await this.prisma.activity.create({
      data: {
        issueId,
        userId,
        action: ActivityAction.ATTACHED,
        newValue: fileNames,
      },
    });

    return attachments;
  }

  async findByIssue(issueId: string, userId: string) {
    const issue = await this.prisma.issue.findUnique({
      where: { id: issueId },
      include: { project: { select: { workspaceId: true } } },
    });
    if (!issue) throw new NotFoundException(MSG.ERROR.ISSUE_NOT_FOUND);

    await this.workspacesService.assertMember(issue.project.workspaceId, userId);

    return this.prisma.attachment.findMany({
      where: { issueId },
      include: { uploadedBy: USER_SELECT_BASIC },
      orderBy: { createdAt: 'desc' },
    });
  }

  async delete(attachmentId: string, userId: string) {
    const attachment = await this.prisma.attachment.findUnique({
      where: { id: attachmentId },
    });
    if (!attachment) throw new NotFoundException(MSG.ERROR.ATTACHMENT_NOT_FOUND);

    if (attachment.uploadedById !== userId) {
      throw new ForbiddenException(MSG.ERROR.NOT_AUTHOR);
    }

    // eslint-disable-next-line @typescript-eslint/no-unsafe-call
    await deleteFile(attachment.fileUrl);

    return this.prisma.attachment.delete({ where: { id: attachmentId } });
  }
}

import {
  Body,
  Controller,
  Delete,
  Get,
  Param,
  Patch,
  Post,
} from '@nestjs/common';
import { ApiOperation, ApiTags } from '@nestjs/swagger';
import { ENDPOINTS, MSG } from '@/core/constants';
import { CurrentUser } from '@/core/decorators';
import { AuthUser } from '@/core/types';
import { CreateColumnDto, UpdateColumnDto, ReorderColumnsDto } from './dto';
import { BoardsService } from './boards.service';

const E = ENDPOINTS.BOARDS;

@ApiTags('Boards')
@Controller(E.BASE)
export class BoardsController {
  constructor(private boardsService: BoardsService) {}

  @Get(E.BY_PROJECT)
  @ApiOperation({ summary: 'Get board by project ID (with columns & issues)' })
  findByProject(@Param('projectId') projectId: string, @CurrentUser() user: AuthUser) {
    return this.boardsService.findByProject(projectId, user.id);
  }

  @Post(E.COLUMNS)
  @ApiOperation({ summary: 'Add column to board' })
  async addColumn(
    @Param('boardId') boardId: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: CreateColumnDto,
  ) {
    const column = await this.boardsService.addColumn(boardId, user.id, dto);
    return { message: MSG.SUCCESS.COLUMN_CREATED, column };
  }

  @Patch(E.COLUMN_BY_ID)
  @ApiOperation({ summary: 'Update column' })
  async updateColumn(
    @Param('boardId') boardId: string,
    @Param('columnId') columnId: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: UpdateColumnDto,
  ) {
    const column = await this.boardsService.updateColumn(boardId, columnId, user.id, dto);
    return { message: MSG.SUCCESS.COLUMN_UPDATED, column };
  }

  @Delete(E.COLUMN_BY_ID)
  @ApiOperation({ summary: 'Delete column' })
  async deleteColumn(
    @Param('boardId') boardId: string,
    @Param('columnId') columnId: string,
    @CurrentUser() user: AuthUser,
  ) {
    await this.boardsService.deleteColumn(boardId, columnId, user.id);
    return { message: MSG.SUCCESS.COLUMN_DELETED };
  }

  @Patch(E.REORDER_COLUMNS)
  @ApiOperation({ summary: 'Reorder columns' })
  async reorderColumns(
    @Param('boardId') boardId: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: ReorderColumnsDto,
  ) {
    const columns = await this.boardsService.reorderColumns(boardId, user.id, dto);
    return { message: MSG.SUCCESS.COLUMNS_REORDERED, columns };
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { StatusCategory } from '@prisma/client';
import { MSG } from '@/core/constants';
import { PrismaService } from '@/core/database/prisma.service';
import { WorkspacesService } from '@/modules/workspaces/workspaces.service';
import { CreateColumnDto, UpdateColumnDto, ReorderColumnsDto } from './dto';

const DEFAULT_COLUMNS = [
  { name: 'To Do', category: StatusCategory.TODO, position: 0 },
  { name: 'In Progress', category: StatusCategory.IN_PROGRESS, position: 1 },
  { name: 'Done', category: StatusCategory.DONE, position: 2 },
];

@Injectable()
export class BoardsService {
  constructor(
    private prisma: PrismaService,
    private workspacesService: WorkspacesService,
  ) {}

  async createDefaultBoard(projectId: string, projectName: string, type: string) {
    return this.prisma.board.create({
      data: {
        name: `${projectName} Board`,
        projectId,
        type: type as any,
        columns: { create: DEFAULT_COLUMNS },
      },
      include: { columns: { orderBy: { position: 'asc' } } },
    });
  }

  async findByProject(projectId: string, userId: string) {
    const project = await this.prisma.project.findUnique({
      where: { id: projectId },
    });
    if (!project) throw new NotFoundException(MSG.ERROR.PROJECT_NOT_FOUND);

    await this.workspacesService.assertMember(project.workspaceId, userId);

    return this.prisma.board.findUnique({
      where: { projectId },
      include: {
        columns: {
          orderBy: { position: 'asc' },
          include: {
            issues: {
              orderBy: { position: 'asc' },
              include: {
                assignee: { select: { id: true, name: true, image: true } },
                labels: { include: { label: true } },
              },
            },
          },
        },
        sprints: { orderBy: { createdAt: 'desc' } },
      },
    });
  }

  // ─── Columns ──────────────────────────────────────────

  async addColumn(boardId: string, userId: string, dto: CreateColumnDto) {
    const board = await this.assertBoardAccess(boardId, userId);

    const maxPosition = await this.prisma.boardColumn.aggregate({
      where: { boardId },
      _max: { position: true },
    });

    return this.prisma.boardColumn.create({
      data: {
        boardId: board.id,
        name: dto.name,
        category: dto.category ?? StatusCategory.IN_PROGRESS,
        position: (maxPosition._max.position ?? -1) + 1,
        wipLimit: dto.wipLimit,
      },
    });
  }

  async updateColumn(boardId: string, columnId: string, userId: string, dto: UpdateColumnDto) {
    await this.assertBoardAccess(boardId, userId);

    const column = await this.prisma.boardColumn.findUnique({ where: { id: columnId } });
    if (!column || column.boardId !== boardId) {
      throw new NotFoundException(MSG.ERROR.COLUMN_NOT_FOUND);
    }

    return this.prisma.boardColumn.update({
      where: { id: columnId },
      data: {
        ...(dto.name !== undefined && { name: dto.name }),
        ...(dto.category !== undefined && { category: dto.category }),
        ...(dto.wipLimit !== undefined && { wipLimit: dto.wipLimit }),
      },
    });
  }

  async deleteColumn(boardId: string, columnId: string, userId: string) {
    await this.assertBoardAccess(boardId, userId);

    const column = await this.prisma.boardColumn.findUnique({ where: { id: columnId } });
    if (!column || column.boardId !== boardId) {
      throw new NotFoundException(MSG.ERROR.COLUMN_NOT_FOUND);
    }

    return this.prisma.boardColumn.delete({ where: { id: columnId } });
  }

  async reorderColumns(boardId: string, userId: string, dto: ReorderColumnsDto) {
    await this.assertBoardAccess(boardId, userId);

    await this.prisma.$transaction(
      dto.columnIds.map((id, index) =>
        this.prisma.boardColumn.update({
          where: { id },
          data: { position: index },
        }),
      ),
    );

    return this.prisma.boardColumn.findMany({
      where: { boardId },
      orderBy: { position: 'asc' },
    });
  }

  // ─── Helpers ──────────────────────────────────────────

  private async assertBoardAccess(boardId: string, userId: string) {
    const board = await this.prisma.board.findUnique({
      where: { id: boardId },
      include: { project: { select: { workspaceId: true } } },
    });
    if (!board) throw new NotFoundException(MSG.ERROR.BOARD_NOT_FOUND);

    await this.workspacesService.assertMember(board.project.workspaceId, userId);
    return board;
  }
}

import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsEnum, IsInt, IsNotEmpty, IsOptional, IsString, MaxLength, Min } from 'class-validator';
import { StatusCategory } from '@prisma/client';

export class CreateColumnDto {
  @ApiProperty({ example: 'In Review' })
  @IsString()
  @IsNotEmpty()
  @MaxLength(50)
  name!: string;

  @ApiPropertyOptional({ enum: StatusCategory, example: StatusCategory.IN_PROGRESS })
  @IsEnum(StatusCategory)
  @IsOptional()
  category?: StatusCategory;

  @ApiPropertyOptional({ example: 5, description: 'WIP limit for Kanban' })
  @IsInt()
  @Min(1)
  @IsOptional()
  wipLimit?: number;
}

import { ApiProperty } from '@nestjs/swagger';
import { IsArray, IsString } from 'class-validator';

export class ReorderColumnsDto {
  @ApiProperty({ example: ['col-uuid-1', 'col-uuid-2', 'col-uuid-3'], description: 'Column IDs in new order' })
  @IsArray()
  @IsString({ each: true })
  columnIds!: string[];
}

import { ApiPropertyOptional } from '@nestjs/swagger';
import { IsEnum, IsInt, IsOptional, IsString, MaxLength, Min } from 'class-validator';
import { StatusCategory } from '@prisma/client';

export class UpdateColumnDto {
  @ApiPropertyOptional({ example: 'Testing' })
  @IsString()
  @IsOptional()
  @MaxLength(50)
  name?: string;

  @ApiPropertyOptional({ enum: StatusCategory })
  @IsEnum(StatusCategory)
  @IsOptional()
  category?: StatusCategory;

  @ApiPropertyOptional({ example: 5 })
  @IsInt()
  @Min(1)
  @IsOptional()
  wipLimit?: number | null;
}

