    return this.commentsService.findByIssue(issueId);
  }
}

@ApiTags('Comments')
@Controller(ENDPOINTS.COMMENTS.BASE)
export class CommentsManageController {
  constructor(private commentsService: CommentsService) {}

  @Patch(ENDPOINTS.COMMENTS.BY_ID)
  @ApiOperation({ summary: 'Update own comment' })
  async update(
    @Param('id') id: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: UpdateCommentDto,
  ) {
    const comment = await this.commentsService.update(id, user.id, dto);
    return { message: MSG.SUCCESS.COMMENT_UPDATED, comment };
  }

  @Delete(ENDPOINTS.COMMENTS.BY_ID)
  @ApiOperation({ summary: 'Delete own comment' })
  async delete(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    await this.commentsService.delete(id, user.id);
    return { message: MSG.SUCCESS.COMMENT_DELETED };
  }
}

import { Module } from '@nestjs/common';
import { CommentsController, CommentsManageController } from './comments.controller';
import { CommentsService } from './comments.service';

@Module({
  controllers: [CommentsController, CommentsManageController],
  providers: [CommentsService],
})
export class CommentsModule {}

import { ForbiddenException, Injectable, NotFoundException } from '@nestjs/common';
import { ActivityAction } from '@prisma/client';
import { MSG, USER_SELECT_BASIC } from '@/core/constants';
import { PrismaService } from '@/core/database/prisma.service';
import { CreateCommentDto, UpdateCommentDto } from './dto';

@Injectable()
export class CommentsService {
  constructor(private prisma: PrismaService) {}

  async create(issueId: string, userId: string, dto: CreateCommentDto) {
    const issue = await this.prisma.issue.findUnique({ where: { id: issueId } });
    if (!issue) throw new NotFoundException(MSG.ERROR.ISSUE_NOT_FOUND);

    const comment = await this.prisma.comment.create({
      data: {
        issueId,
        authorId: userId,
        content: dto.content,
        parentId: dto.parentId,
      },
      include: {
        author: USER_SELECT_BASIC,
        replies: { include: { author: USER_SELECT_BASIC } },
      },
    });

    await this.prisma.activity.create({
      data: {
        issueId,
        userId,
        action: ActivityAction.COMMENTED,
      },
    });

    return comment;
  }

  async findByIssue(issueId: string) {
    return this.prisma.comment.findMany({
      where: { issueId, parentId: null },
      include: {
        author: USER_SELECT_BASIC,
        replies: {
          include: { author: USER_SELECT_BASIC },
          orderBy: { createdAt: 'asc' },
        },
      },
      orderBy: { createdAt: 'asc' },
    });
  }

  async update(commentId: string, userId: string, dto: UpdateCommentDto) {
    const comment = await this.prisma.comment.findUnique({ where: { id: commentId } });
    if (!comment) throw new NotFoundException(MSG.ERROR.COMMENT_NOT_FOUND);
    if (comment.authorId !== userId) throw new ForbiddenException(MSG.ERROR.NOT_AUTHOR);

    return this.prisma.comment.update({
      where: { id: commentId },
      data: { content: dto.content },
      include: { author: USER_SELECT_BASIC },
    });
  }

  async delete(commentId: string, userId: string) {
    const comment = await this.prisma.comment.findUnique({ where: { id: commentId } });
    if (!comment) throw new NotFoundException(MSG.ERROR.COMMENT_NOT_FOUND);
    if (comment.authorId !== userId) throw new ForbiddenException(MSG.ERROR.NOT_AUTHOR);

    return this.prisma.comment.delete({ where: { id: commentId } });
  }
}

