import { Body, Controller, Delete, Get, Param, Patch, Post } from '@nestjs/common';
import { ApiOperation, ApiTags } from '@nestjs/swagger';
import { ENDPOINTS, MSG } from '@/core/constants';
import { CurrentUser } from '@/core/decorators';
import { AuthUser } from '@/core/types';
import { CreateSprintDto, UpdateSprintDto } from './dto';
import { SprintsService } from './sprints.service';

const E = ENDPOINTS.SPRINTS;

@ApiTags('Sprints')
@Controller(E.BASE)
export class SprintsController {
  constructor(private sprintsService: SprintsService) {}

  @Post()
  @ApiOperation({ summary: 'Create a new sprint' })
  async create(@CurrentUser() user: AuthUser, @Body() dto: CreateSprintDto) {
    const sprint = await this.sprintsService.create(user.id, dto);
    return { message: MSG.SUCCESS.SPRINT_CREATED, sprint };
  }

  @Get(E.BY_ID)
  @ApiOperation({ summary: 'Get sprint by ID with issues' })
  findOne(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    return this.sprintsService.findById(id, user.id);
  }

  @Patch(E.BY_ID)
  @ApiOperation({ summary: 'Update sprint' })
  async update(
    @Param('id') id: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: UpdateSprintDto,
  ) {
    const sprint = await this.sprintsService.update(id, user.id, dto);
    return { message: MSG.SUCCESS.SPRINT_UPDATED, sprint };
  }

  @Post(E.START)
  @ApiOperation({ summary: 'Start sprint' })
  async start(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    const sprint = await this.sprintsService.start(id, user.id);
    return { message: MSG.SUCCESS.SPRINT_STARTED, sprint };
  }

  @Post(E.COMPLETE)
  @ApiOperation({ summary: 'Complete sprint (moves incomplete issues to backlog)' })
  async complete(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    const sprint = await this.sprintsService.complete(id, user.id);
    return { message: MSG.SUCCESS.SPRINT_COMPLETED, sprint };
  }

  @Get(E.BURNDOWN)
  @ApiOperation({ summary: 'Get sprint burndown chart data' })
  getBurndown(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    return this.sprintsService.getBurndown(id, user.id);
  }

  @Delete(E.BY_ID)
  @ApiOperation({ summary: 'Delete sprint' })
  async delete(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    await this.sprintsService.delete(id, user.id);
    return { message: MSG.SUCCESS.SPRINT_DELETED };
  }
}

import {
  BadRequestException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { SprintStatus, StatusCategory } from '@prisma/client';
import { MSG } from '@/core/constants';
import { PrismaService } from '@/core/database/prisma.service';
import { WorkspacesService } from '@/modules/workspaces/workspaces.service';
import { CreateSprintDto, UpdateSprintDto } from './dto';

@Injectable()
export class SprintsService {
  constructor(
    private prisma: PrismaService,
    private workspacesService: WorkspacesService,
  ) {}

  async create(userId: string, dto: CreateSprintDto) {
    await this.assertBoardAccess(dto.boardId, userId);

    return this.prisma.sprint.create({
      data: {
        boardId: dto.boardId,
        name: dto.name,
        goal: dto.goal,
        startDate: dto.startDate ? new Date(dto.startDate) : undefined,
        endDate: dto.endDate ? new Date(dto.endDate) : undefined,
      },
    });
  }

  async findById(sprintId: string, userId: string) {
    const sprint = await this.prisma.sprint.findUnique({
      where: { id: sprintId },
      include: {
        issues: {
          orderBy: { position: 'asc' },
          include: {
            assignee: { select: { id: true, name: true, image: true } },
            boardColumn: { select: { id: true, name: true, category: true } },
          },
        },
        _count: { select: { issues: true } },
      },
    });
    if (!sprint) throw new NotFoundException(MSG.ERROR.SPRINT_NOT_FOUND);

    await this.assertBoardAccess(sprint.boardId, userId);
    return sprint;
  }

  async update(sprintId: string, userId: string, dto: UpdateSprintDto) {
    const sprint = await this.findById(sprintId, userId);

    return this.prisma.sprint.update({
      where: { id: sprint.id },
      data: {
        ...(dto.name !== undefined && { name: dto.name }),
        ...(dto.goal !== undefined && { goal: dto.goal }),
        ...(dto.startDate !== undefined && { startDate: new Date(dto.startDate) }),
        ...(dto.endDate !== undefined && { endDate: new Date(dto.endDate) }),
      },
    });
  }

  async start(sprintId: string, userId: string) {
    const sprint = await this.findById(sprintId, userId);

    // Check no other active sprint on same board
    const activeSprint = await this.prisma.sprint.findFirst({
      where: { boardId: sprint.boardId, status: SprintStatus.ACTIVE },
    });
    if (activeSprint) throw new BadRequestException(MSG.ERROR.SPRINT_ALREADY_ACTIVE);

    return this.prisma.sprint.update({
      where: { id: sprint.id },
      data: {
        status: SprintStatus.ACTIVE,
        startDate: sprint.startDate ?? new Date(),
      },
    });
  }

  async complete(sprintId: string, userId: string) {
    const sprint = await this.findById(sprintId, userId);
    if (sprint.status !== SprintStatus.ACTIVE) {
      throw new BadRequestException(MSG.ERROR.SPRINT_NOT_ACTIVE);
    }

    // Move incomplete issues back to backlog (unset sprintId)
    await this.prisma.issue.updateMany({
      where: {
        sprintId: sprint.id,
        boardColumn: { category: { not: StatusCategory.DONE } },
      },
      data: { sprintId: null },
    });

    return this.prisma.sprint.update({
      where: { id: sprint.id },
      data: { status: SprintStatus.COMPLETED, endDate: new Date() },
    });
  }

  async delete(sprintId: string, userId: string) {
    const sprint = await this.findById(sprintId, userId);

    // Unassign issues from this sprint
    await this.prisma.issue.updateMany({
      where: { sprintId: sprint.id },
      data: { sprintId: null },
    });

    return this.prisma.sprint.delete({ where: { id: sprint.id } });
  }

  async getBurndown(sprintId: string, userId: string) {
    const sprint = await this.findById(sprintId, userId);
    if (!sprint.startDate) return { totalPoints: 0, days: [] };

    const startDate = new Date(sprint.startDate);
    const endDate = sprint.endDate ? new Date(sprint.endDate) : new Date();

    // All issues in this sprint
    const issues = sprint.issues;
    const totalPoints = issues.reduce((sum, i) => sum + (i.storyPoints ?? 1), 0);

    // Build daily burndown
    const totalDays = Math.max(1, Math.ceil((endDate.getTime() - startDate.getTime()) / 86400000));
    const pointsPerDay = totalPoints / totalDays;

    const days: { date: string; ideal: number; actual: number }[] = [];

    for (let d = 0; d <= totalDays; d++) {
      const currentDate = new Date(startDate);
      currentDate.setDate(currentDate.getDate() + d);
      const dateStr = currentDate.toISOString().slice(0, 10);

      // Count points completed by this date (issues with completedAt <= currentDate)
      const donePoints = issues
        .filter((i) => i.completedAt && new Date(i.completedAt).toISOString().slice(0, 10) <= dateStr)
        .reduce((sum, i) => sum + (i.storyPoints ?? 1), 0);

      days.push({
        date: dateStr,
        ideal: Math.max(0, Math.round((totalPoints - pointsPerDay * d) * 10) / 10),
        actual: totalPoints - donePoints,
      });
    }

    return { totalPoints, days };
  }

  // ─── Helpers ──────────────────────────────────────────

  private async assertBoardAccess(boardId: string, userId: string) {
    const board = await this.prisma.board.findUnique({
      where: { id: boardId },
      include: { project: { select: { workspaceId: true } } },
    });
    if (!board) throw new NotFoundException(MSG.ERROR.BOARD_NOT_FOUND);

    await this.workspacesService.assertMember(board.project.workspaceId, userId);
    return board;
  }
}

