export class WorklogsModule {}

import { ForbiddenException, Injectable, NotFoundException } from '@nestjs/common';
import { ActivityAction } from '@prisma/client';
import { MSG, USER_SELECT_BASIC } from '@/core/constants';
import { PrismaService } from '@/core/database/prisma.service';
import { CreateWorklogDto, UpdateWorklogDto } from './dto';

@Injectable()
export class WorklogsService {
  constructor(private prisma: PrismaService) {}

  async create(issueId: string, userId: string, dto: CreateWorklogDto) {
    const issue = await this.prisma.issue.findUnique({ where: { id: issueId } });
    if (!issue) throw new NotFoundException(MSG.ERROR.ISSUE_NOT_FOUND);

    const worklog = await this.prisma.worklog.create({
      data: {
        issueId,
        userId,
        timeSpent: dto.timeSpent,
        startedAt: new Date(dto.startedAt),
        description: dto.description,
      },
      include: { user: USER_SELECT_BASIC },
    });

    await this.prisma.activity.create({
      data: {
        issueId,
        userId,
        action: ActivityAction.LOGGED_WORK,
        newValue: `${dto.timeSpent}s`,
      },
    });

    return worklog;
  }

  async findByIssue(issueId: string) {
    return this.prisma.worklog.findMany({
      where: { issueId },
      include: { user: USER_SELECT_BASIC },
      orderBy: { startedAt: 'desc' },
    });
  }

  async update(worklogId: string, userId: string, dto: UpdateWorklogDto) {
    const worklog = await this.prisma.worklog.findUnique({ where: { id: worklogId } });
    if (!worklog) throw new NotFoundException(MSG.ERROR.WORKLOG_NOT_FOUND);
    if (worklog.userId !== userId) throw new ForbiddenException(MSG.ERROR.NOT_AUTHOR);

    return this.prisma.worklog.update({
      where: { id: worklogId },
      data: {
        ...(dto.timeSpent !== undefined && { timeSpent: dto.timeSpent }),
        ...(dto.startedAt !== undefined && { startedAt: new Date(dto.startedAt) }),
        ...(dto.description !== undefined && { description: dto.description }),
      },
      include: { user: USER_SELECT_BASIC },
    });
  }

  async delete(worklogId: string, userId: string) {
    const worklog = await this.prisma.worklog.findUnique({ where: { id: worklogId } });
    if (!worklog) throw new NotFoundException(MSG.ERROR.WORKLOG_NOT_FOUND);
    if (worklog.userId !== userId) throw new ForbiddenException(MSG.ERROR.NOT_AUTHOR);

    return this.prisma.worklog.delete({ where: { id: worklogId } });
  }
}

import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsEnum, IsNotEmpty, IsOptional, IsString, Matches } from 'class-validator';
import { WorkspaceRole } from '@prisma/client';
import { REGEX } from '@/core/constants';

export class AddWorkspaceMemberDto {
  @ApiProperty({ example: 'john@example.com' })
  @IsString()
  @IsNotEmpty()
  @Matches(REGEX.EMAIL)
  email!: string;

  @ApiPropertyOptional({ enum: WorkspaceRole, example: WorkspaceRole.MEMBER })
  @IsEnum(WorkspaceRole)
  @IsOptional()
  role?: WorkspaceRole;
}

import { ApiProperty } from '@nestjs/swagger';
import { IsEnum } from 'class-validator';
import { WorkspaceRole } from '@prisma/client';

export class UpdateWorkspaceMemberDto {
  @ApiProperty({ enum: WorkspaceRole, example: WorkspaceRole.ADMIN })
  @IsEnum(WorkspaceRole)
  role!: WorkspaceRole;
}

import {
  Body,
  Controller,
  Delete,
  Get,
  Param,
  Patch,
  Post,
} from '@nestjs/common';
import { ApiOperation, ApiTags } from '@nestjs/swagger';
import { ENDPOINTS, MSG } from '@/core/constants';
import { CurrentUser } from '@/core/decorators';
import { AuthUser } from '@/core/types';
import {
  AddWorkspaceMemberDto,
  CreateWorkspaceDto,
  UpdateWorkspaceDto,
  UpdateWorkspaceMemberDto,
} from './dto';
import { WorkspacesService } from './workspaces.service';

const E = ENDPOINTS.WORKSPACES;

@ApiTags('Workspaces')
@Controller(E.BASE)
export class WorkspacesController {
  constructor(private workspacesService: WorkspacesService) {}

  @Post()
  @ApiOperation({ summary: 'Create a new workspace' })
  async create(@CurrentUser() user: AuthUser, @Body() dto: CreateWorkspaceDto) {
    const workspace = await this.workspacesService.create(user.id, dto);
    return { message: MSG.SUCCESS.WORKSPACE_CREATED, workspace };
  }

  @Get()
  @ApiOperation({ summary: 'List workspaces for current user' })
  findAll(@CurrentUser() user: AuthUser) {
    return this.workspacesService.findAllByUser(user.id);
  }

  @Get(E.BY_ID)
  @ApiOperation({ summary: 'Get workspace by ID' })
  findOne(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    return this.workspacesService.findById(id, user.id);
  }

  @Patch(E.BY_ID)
  @ApiOperation({ summary: 'Update workspace (Owner/Admin)' })
  async update(
    @Param('id') id: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: UpdateWorkspaceDto,
  ) {
    const workspace = await this.workspacesService.update(id, user.id, dto);
    return { message: MSG.SUCCESS.WORKSPACE_UPDATED, workspace };
  }

  @Delete(E.BY_ID)
  @ApiOperation({ summary: 'Delete workspace (Owner only)' })
  async delete(@Param('id') id: string, @CurrentUser() user: AuthUser) {
    await this.workspacesService.delete(id, user.id);
    return { message: MSG.SUCCESS.WORKSPACE_DELETED };
  }

  // ─── Members ──────────────────────────────────────────

  @Post(`${E.BY_ID}/${E.MEMBERS}`)
  @ApiOperation({ summary: 'Add member to workspace (Owner/Admin)' })
  async addMember(
    @Param('id') id: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: AddWorkspaceMemberDto,
  ) {
    const member = await this.workspacesService.addMember(id, user.id, dto);
    return { message: MSG.SUCCESS.MEMBER_ADDED, member };
  }

  @Patch(`${E.BY_ID}/${E.MEMBER_BY_ID}`)
  @ApiOperation({ summary: 'Update member role (Owner/Admin)' })
  async updateMember(
    @Param('id') id: string,
    @Param('memberId') memberId: string,
    @CurrentUser() user: AuthUser,
    @Body() dto: UpdateWorkspaceMemberDto,
  ) {
    const member = await this.workspacesService.updateMember(id, memberId, user.id, dto);
    return { message: MSG.SUCCESS.MEMBER_UPDATED, member };
  }

  @Delete(`${E.BY_ID}/${E.MEMBER_BY_ID}`)
  @ApiOperation({ summary: 'Remove member from workspace (Owner/Admin)' })
  async removeMember(
    @Param('id') id: string,
    @Param('memberId') memberId: string,
    @CurrentUser() user: AuthUser,
  ) {
    await this.workspacesService.removeMember(id, memberId, user.id);
    return { message: MSG.SUCCESS.MEMBER_REMOVED };
  }
}

